import json,glob,os
from collections import defaultdict
PROG='/sandbox/work/progress.json'
votes=[]
for f in sorted(glob.glob('/sandbox/work/verdict-*.json')):
    try: votes.append(json.load(open(f)))
    except Exception: pass
if not votes:
    try: votes=[json.load(open('/sandbox/work/verdict.json'))]
    except Exception: votes=[]
if not votes:
    print(json.dumps({'meets_criteria':False,'stalled':False,'recommend_restart':False,'votes':0,'feedback':'no verdict files'}));raise SystemExit
cp=defaultdict(list)
for v in votes:
    for c in (v.get('criteria') or []):
        if isinstance(c,dict) and c.get('id') is not None:
            cp[str(c.get('id'))].append(bool(c.get('passes')))
# skeptical aggregation: a criterion passes only if ALL votes pass it
agg={cid: (all(pl) and len(pl)>0) for cid,pl in cp.items()}
total=len(agg); passed=sum(1 for ok in agg.values() if ok)
res = total>0 and passed==total
rr=[bool(v.get('recommend_restart')) for v in votes]
recommend_restart = (sum(1 for x in rr if x) > (len(rr)/2.0)) and not res
# update contract.json passes from the aggregate
try:
    con=json.load(open('/sandbox/work/contract.json'))
    for c in (con.get('criteria') or []):
        if isinstance(c,dict) and str(c.get('id')) in agg: c['passes']=agg[str(c.get('id'))]
    json.dump(con,open('/sandbox/work/contract.json','w'))
except Exception: pass
fb=' || '.join(str(v.get('feedback') or v.get('summary') or '') for v in votes)[:400]
try: p=json.load(open(PROG))
except Exception: p={'baseline':'unknown','log':[]}
p.setdefault('log',[]).append({'iteration':len(p.get('log',[])),'criteriaPassed':passed,'criteriaTotal':total,'allPass':res,'votes':len(votes),'recommendRestart':recommend_restart,'note':fb[:200]})
json.dump(p,open(PROG,'w'))
K=3; seq=[e.get('criteriaPassed',0) for e in p['log'] if 'criteriaPassed' in e]; stalled=False
if not res and len(seq)>K: stalled = max(seq[-K:]) <= max(seq[:-K])
print(json.dumps({'meets_criteria':res,'stalled':stalled,'recommend_restart':recommend_restart,'passed':passed,'total':total,'votes':len(votes),'feedback':fb[:300]}))
